<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\ScannerMovementRepositoryInterface;use App\DTO\ControlEscaneres\ScannerMovementCreateData;use App\Domain\ControlEscaneres\{ScannerMovement,ScannerFolio,MovementStatus};
final class PdoScannerMovementRepository extends AbstractPdoRepository implements ScannerMovementRepositoryInterface{private function map(array$r):ScannerMovement{return new ScannerMovement((int)$r['id'],(int)$r['scanner_id'],new ScannerFolio($r['folio']),new MovementStatus($r['estado']));}private function one(string$q,array$p):?ScannerMovement{$r=$this->stmt($q,$p)->fetch(\PDO::FETCH_ASSOC);return is_array($r)?$this->map($r):null;}public function findById(int$id):?ScannerMovement{return$this->one('SELECT * FROM scanner_movimientos WHERE id=:id',['id'=>$id]);}public function findOpenByScannerId(int$id):?ScannerMovement{return$this->one("SELECT * FROM scanner_movimientos WHERE scanner_id=:id AND estado='abierto'",['id'=>$id]);}public function hasOpenMovement(int$id):bool{return$this->findOpenByScannerId($id)!==null;}public function create(ScannerMovementCreateData$d):ScannerMovement{$this->stmt("INSERT INTO scanner_movimientos(scanner_id,folio,estado,persona_entrega_nombre,numero_empleado,turno,entregado_at,entrega_registrada_por)VALUES(:s,:f,'abierto',:p,:e,:t,:a,:u)",['s'=>$d->scannerId,'f'=>$d->folio->value,'p'=>$d->personName,'e'=>$d->employeeNumber,'t'=>$d->shift,'a'=>$d->deliveredAt->format('Y-m-d H:i:s.u'),'u'=>$d->actor->userId]);return$this->findById((int)$this->pdo->lastInsertId());}public function closeAsReturned(int$id,\DateTimeImmutable$a,int$u,string$r):void{$this->stmt("UPDATE scanner_movimientos SET estado='devuelto',recibido_at=:a,recepcion_registrada_por=:u,devolucion_recibida_por_nombre=:r WHERE id=:id",compact('id','u','r')+['a'=>$a->format('Y-m-d H:i:s.u')]);}public function cancel(int$id,int$u,string$r):void{$this->stmt("UPDATE scanner_movimientos SET estado='cancelado',cancelado_por=:u,motivo_cancelacion=:r,cancelado_at=CURRENT_TIMESTAMP WHERE id=:id",compact('id','u','r'));}public function markOverdue(\DateTimeImmutable$a):int{$s=$this->stmt("UPDATE scanner_movimientos SET estado='vencido' WHERE estado='abierto' AND vence_at<:a",['a'=>$a->format('Y-m-d H:i:s.u')]);return$s->rowCount();}private function many(string$q,array$p=[]):array{return array_map(fn($r)=>$this->map($r),$this->stmt($q,$p)->fetchAll(\PDO::FETCH_ASSOC));}public function listByScannerId(int$id):array{return$this->many('SELECT * FROM scanner_movimientos WHERE scanner_id=:id',['id'=>$id]);}public function listOpen():array{return$this->many("SELECT * FROM scanner_movimientos WHERE estado='abierto'");}public function countOpen():int{return count($this->listOpen());}public function countOverdue(\DateTimeImmutable$a):int{return(int)$this->stmt("SELECT COUNT(*) FROM scanner_movimientos WHERE estado='abierto' AND vence_at<:a",['a'=>$a->format('Y-m-d H:i:s.u')])->fetchColumn();}public function lockOpenMovementForUpdate(int$id):?ScannerMovement{return$this->one("SELECT * FROM scanner_movimientos WHERE scanner_id=:id AND estado='abierto'".$this->forUpdate(),['id'=>$id]);}}
